        qs!.AddInternalSchedulerListener(this);

        IJob job;

        try
        {
            job = qs.JobFactory.NewJob(firedTriggerBundle, scheduler);
        }
        catch (SchedulerException se)
        {
            await qs.NotifySchedulerListenersError($"An error occurred instantiating job to be executed. job= '{firedTriggerBundle.JobDetail.Key}'", se, cancellationToken).ConfigureAwait(false);
