using Microsoft.Extensions.Options;
using Quartz;
using Quartz.Core;
using Quartz.Impl;
using Quartz.Simpl;
using Quartz.Spi;

var asyncLocal = new AsyncLocal<string>();

var schedulerBuilder = SchedulerBuilder.Create().Build();
var scheduler = await schedulerBuilder.GetScheduler();

var jobDetail = JobBuilder.Create<TestAsyncLocalJob>()
    .WithIdentity("testJob", "testGroup")
    .StoreDurably()
    .Build();

var trigger = (IOperableTrigger) TriggerBuilder.Create()
    .ForJob(jobDetail.Key)
    .WithSimpleSchedule()
    .StartNow()
    .Build();
trigger.FireInstanceId = "fire-instance-id";
trigger.SetNextFireTimeUtc(DateTimeOffset.UtcNow.AddSeconds(10));

var bundle = new TriggerFiredBundle(jobDetail, trigger, null, false, DateTimeOffset.UtcNow, null, null, null);

var schedulerImpl = (StdScheduler) scheduler;
var shell = new JobRunShell(scheduler, bundle);

// Set up the factory
schedulerImpl.sched.JobFactory = new AsyncLocalTestJobFactory(new TestServiceProvider(), Options.Create(new QuartzOptions()), asyncLocal);

await shell.Initialize(schedulerImpl.sched);
await shell.Run();

var result = TestAsyncLocalJob.CapturedAsyncLocalValue;

if (result == "test-value-set-in-factory")
{
    Console.WriteLine("SUCCESS: AsyncLocal value flowed correctly from NewJob to Execute!");
}
else
{
    Console.WriteLine($"FAILURE: AsyncLocal value was '{result ?? "null"}' instead of 'test-value-set-in-factory'");
}

await scheduler.Shutdown();

public class TestAsyncLocalJob : IJob
{
    public static string? CapturedAsyncLocalValue { get; set; }

    public ValueTask Execute(IJobExecutionContext context)
    {
        CapturedAsyncLocalValue = AsyncLocalTestJobFactory.AsyncLocal.Value;
        return default;
    }
}

public class AsyncLocalTestJobFactory : IJobFactory
{
    public static AsyncLocal<string> AsyncLocal { get; private set; } = null!;

    public AsyncLocalTestJobFactory(IServiceProvider serviceProvider, IOptions<QuartzOptions> options, AsyncLocal<string> asyncLocal)
    {
        AsyncLocal = asyncLocal;
    }

    public IJob NewJob(TriggerFiredBundle bundle, IScheduler scheduler)
    {
        AsyncLocal.Value = "test-value-set-in-factory";
        return new TestAsyncLocalJob();
    }

    public ValueTask ReturnJob(IJob job) => default;
}

public class TestServiceProvider : IServiceProvider
{
    public object GetService(Type serviceType)
    {
        return Activator.CreateInstance(serviceType)!;
    }
}
ENDOFTEST
