using Microsoft.Extensions.Options;
using Quartz;
using Quartz.Core;
using Quartz.Impl;
using Quartz.Impl.Triggers;
using Quartz.Spi;

var asyncLocal = new AsyncLocal<string>();

var schedulerBuilder = SchedulerBuilder.Create().Build();
var scheduler = await schedulerBuilder.GetScheduler();

var jobDetail = JobBuilder.Create<TestAsyncLocalJob>()
    .WithIdentity("testJob", "testGroup")
    .StoreDurably()
    .Build();

var trigger = new SimpleTriggerImpl("triggerName", "triggerGroup");
trigger.FireInstanceId = "fire-instance-id";
trigger.SetNextFireTimeUtc(DateTimeOffset.UtcNow.AddSeconds(10));

var bundle = new TriggerFiredBundle(jobDetail, trigger, null, false, DateTimeOffset.UtcNow, null, null, null);

var shell = new JobRunShell(scheduler, bundle);

// We can't set JobFactory on the scheduler directly because StdScheduler is internal
// But we can create our own job factory and use reflection to set it, or just test
// via the quartz scheduler resources directly

// Instead, let's use a different approach: create the QuartzScheduler directly
var resources = new QuartzSchedulerResources();
var qs = new QuartzScheduler(resources);

// Reflection to set JobFactory on QuartzScheduler
var jobFactoryField = typeof(QuartzScheduler).GetField("jobFactory", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
jobFactoryField!.SetValue(qs, new AsyncLocalTestJobFactory(new TestServiceProvider(), Options.Create(new QuartzOptions()), asyncLocal));

